//! Qwen35MoePipeline — distributed-inference forward pass for the
//! `qwen35moe` architecture (Qwen3-Next / Qwen3.6-35B-A3B class).
//!
//! This is a HYBRID model: most layers are Mamba-2 *gated DeltaNet* SSM
//! layers; every `full_attention_interval`-th layer (layers 3, 7, 11, …,
//! 39 for the 35B-A3B) is a standard partial-RoPE GQA full-attention
//! layer. EVERY layer's FFN is a sparse Mixture-of-Experts block (top-8 of
//! 256 routed experts + an always-on sigmoid-gated shared expert).
//!
//! Interface mirrors [`crate::model_gemma4::Gemma4Pipeline`]:
//!   - `from_knot(probe: KnotWeights) -> Result<Self, String>`
//!   - `forward_one(token_id, pos) -> Result<()>`  (stashes `last_logits`)
//!   - `get_logits() -> &[f32]`
//!   - `config.hidden_dim / vocab_size / num_layers`
//!
//! Kernel reuse: big matmuls go through `mat_vec_dispatch_batch` (QType
//! dispatch from `model.rs`); RMSNorm / softmax / RoPE / SiLU come from
//! `math.rs`. The gated-DeltaNet recurrence and the depthwise causal
//! conv1d are implemented inline here (no direct analogue in
//! `model_mamba.rs`, whose SSD step uses a diagonal scalar A; DeltaNet
//! carries a full per-v-head outer-product state `S[d_k, d_v]`).
//!
//! Per-layer type is determined by TENSOR PRESENCE: a layer is
//! full-attention iff `blk_{L}_attn_output_weight` exists in the knot.
//! Full-attn layers carry SEPARATE `attn_q` / `attn_k` / `attn_v` (where
//! `attn_q` fuses [query | output-gate], 2*q_dim rows) + `attn_output`.
//! SSM layers instead carry the fused `attn_qkv` DeltaNet in-projection
//! (q+k+v feeding the conv1d) + `attn_gate` (the z value-gate) and NO
//! `attn_output`. So `attn_output` presence is the clean discriminator.
//!
//! References:
//!   - HF transformers `modeling_qwen3_next.py` (gated DeltaNet recurrence,
//!     RMSNormGated = norm-then-silu-gate, fused q+gate attention, MoE
//!     `norm_topk_prob` + sigmoid-gated shared expert).
//!   - llama.cpp `qwen3next` / `qwen35moe` build graph (GGUF tensor split
//!     conventions for the fused qkv / conv1d / expert tensors).
//!
//! GROUND TRUTH (Qwen3.6-35B-A3B Q8_0): 40 layers, hidden=2048,
//! vocab=248320, rms_eps=1e-6. Full-attn: heads=16, kv=2, head_dim=256,
//! rope_base=1e7, rope_dim_count=64 (partial split-half NeoX), gated o-proj
//! (attn_out *= sigmoid(attn_gate)). SSM: state_size=128, conv_kernel=4,
//! group_count=16 (k-heads), inner_size=4096 (v-dim), time_step_rank=32
//! (v-heads). MoE: 256 experts, top-8, renormalized, moe_ff=512, shared
//! expert moe_ff=512. UNTIED lm_head (`output.weight`). No logit softcap.

use crate::loader::{KnotConfig, KnotWeights};
use crate::math::{dot_product, rms_norm, rope_neox, softmax};
use crate::model::{bytes_to_f32_slice, mat_vec_dispatch_batch, QType};

type Result<T> = std::result::Result<T, String>;

// ── Small local activations (kept inline to avoid cross-module churn) ──
#[inline(always)]
fn sigmoid(x: f32) -> f32 {
    1.0 / (1.0 + (-x).exp())
}
#[inline(always)]
fn silu(x: f32) -> f32 {
    x * sigmoid(x)
}
#[inline(always)]
fn softplus(x: f32) -> f32 {
    if x > 20.0 {
        x
    } else {
        (1.0 + x.exp()).ln()
    }
}

/// Map a GGUF tensor-type string to the crate `QType`. Mirrors the private
/// `model::resolve_type`; re-implemented here because that helper is not
/// `pub`. The 35B-A3B knot is all-Q8_0 weights + F32 norms, but we accept
/// the full K-quant set so re-quantized knots load unchanged.
fn qtype_of(t: &str) -> QType {
    match t {
        "Q4_K" | "Q4_K_S" | "Q4_K_M" | "Q4_K_L" => QType::Q4K,
        "Q5_0" => QType::Q5_0,
        "Q5_K" | "Q5_K_S" | "Q5_K_M" | "Q5_K_L" => QType::Q5K,
        "Q6_K" => QType::Q6K,
        "Q8_0" => QType::Q8_0,
        "IQ2_S" => QType::IQ2S,
        "IQ3_S" => QType::IQ3S,
        "KAIJU1" => QType::KAIJU1,
        "f16" | "fp16" | "F16" | "FP16" | "half" => QType::F16,
        "f32" | "fp32" | "F32" | "FP32" => QType::F32,
        // Mirrors model::resolve_type: unknown quant type must fail loudly
        // at load, never silently reinterpret packed blocks as raw f32.
        other => panic!(
            "qtype_of: unknown tensor quant type {other:?} — no dequant kernel. \
             Supported: Q4_K*, Q5_0, Q5_K*, Q6_K, Q8_0, F16, F32."
        ),
    }
}

/// Bytes-per-(quant)block and elements-per-block for slicing 3-D expert
/// tensors at expert boundaries. Q8_0 = 34 B / 32 elems; F32 = 4 B / 1.
/// (Expert slices in this knot are Q8_0 and the per-expert element count
/// `rows*cols` is a multiple of 32, so every expert slice is block-aligned.)
fn block_layout(q: QType) -> (usize, usize) {
    match q {
        QType::Q8_0 => (34, 32),
        QType::Q6K => (210, 256),
        QType::Q5K => (176, 256),
        QType::Q4K => (144, 256),
        QType::Q5_0 => (22, 32),
        QType::F16 => (2, 1),
        QType::F32 => (4, 1),
        QType::IQ2S => (82, 256),
        QType::IQ3S => (110, 256),
        QType::KAIJU1 => panic!(
            "KAIJU1 tensors are not block-regular; expert slicing unsupported"
        ),
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Config
// ─────────────────────────────────────────────────────────────────────────────

#[derive(Clone, Debug)]
pub struct Qwen35MoeConfig {
    pub arch: String,
    pub hidden_dim: usize,
    pub num_layers: usize,
    pub vocab_size: usize,
    pub rms_norm_eps: f32,

    // Full-attention layers.
    pub num_heads: usize,
    pub num_kv_heads: usize,
    pub head_dim: usize,
    pub rope_theta: f32,
    /// Number of head_dim elements that rotate (partial RoPE). 64 here; the
    /// remaining 192 of each 256-dim head pass through unrotated.
    pub rope_dim_count: usize,
    /// Every `full_attention_interval`-th layer is a full-attention layer
    /// ((l+1) % interval == 0). The rest are SSM layers. Layer kind is
    /// confirmed by tensor presence at load time; this is the fallback.
    pub full_attention_interval: usize,
    pub max_seq_len: usize,

    // SSM (gated DeltaNet) layers.
    /// head_k_dim == head_v_dim == 128.
    pub ssm_state_size: usize,
    /// Causal depthwise conv kernel = 4.
    pub ssm_conv_kernel: usize,
    /// num_k_heads = 16.
    pub ssm_group_count: usize,
    /// value_dim = 4096 (= num_v_heads * state_size = 32 * 128).
    pub ssm_inner_size: usize,
    /// num_v_heads = 32 (== time_step_rank here).
    pub ssm_time_step_rank: usize,

    // MoE FFN (all layers).
    pub num_experts: usize,
    pub num_experts_per_tok: usize,
    pub expert_ff_len: usize,
    pub shared_expert_ff_len: usize,
}

impl Qwen35MoeConfig {
    // Ground-truth defaults for Qwen3.6-35B-A3B. Used when the (new) dedicated
    // KnotConfig fields are not yet wired (see patch list (a) in the handoff
    // report). The integrator should replace each `*_DEFAULT` read below with
    // `k.<field>.unwrap_or(*_DEFAULT)` once the Option<> fields land in
    // loader.rs::KnotConfig, so non-35B qwen35moe variants pick up their own
    // header values. Every default here is VERIFY-confirmed against the actual
    // GGUF header.
    const ROPE_DIM_COUNT_DEFAULT: usize = 64;
    const FULL_ATTENTION_INTERVAL_DEFAULT: usize = 4;
    const SSM_STATE_SIZE_DEFAULT: usize = 128;
    const SSM_CONV_KERNEL_DEFAULT: usize = 4;
    const SSM_GROUP_COUNT_DEFAULT: usize = 16;
    const SSM_INNER_SIZE_DEFAULT: usize = 4096;
    const SSM_TIME_STEP_RANK_DEFAULT: usize = 32;
    const EXPERT_FF_LEN_DEFAULT: usize = 512;
    const SHARED_EXPERT_FF_LEN_DEFAULT: usize = 512;

    pub fn from_knot(k: &KnotConfig) -> Self {
        Self {
            arch: k.arch.clone(),
            hidden_dim: k.hidden_dim,
            num_layers: k.num_layers,
            vocab_size: k.vocab_size,
            rms_norm_eps: k.rms_norm_eps,
            num_heads: k.num_heads,
            num_kv_heads: k.num_kv_heads,
            head_dim: k.head_dim,
            rope_theta: k.rope_theta,
            // The following read GGUF-confirmed defaults today (existing
            // KnotConfig has no dedicated fields). Swap to the new Option<>
            // fields per patch list (a). `d_state`/`d_conv` already exist and
            // carry the SSM state/conv-kernel for this knot, so prefer them.
            rope_dim_count: Self::ROPE_DIM_COUNT_DEFAULT,
            full_attention_interval: Self::FULL_ATTENTION_INTERVAL_DEFAULT,
            max_seq_len: k.max_seq_len.unwrap_or(2048),
            ssm_state_size: k.d_state.unwrap_or(Self::SSM_STATE_SIZE_DEFAULT),
            ssm_conv_kernel: k.d_conv.unwrap_or(Self::SSM_CONV_KERNEL_DEFAULT),
            ssm_group_count: Self::SSM_GROUP_COUNT_DEFAULT,
            ssm_inner_size: Self::SSM_INNER_SIZE_DEFAULT,
            ssm_time_step_rank: Self::SSM_TIME_STEP_RANK_DEFAULT,
            num_experts: k.num_experts.unwrap_or(256),
            num_experts_per_tok: k.num_experts_per_tok.unwrap_or(8),
            expert_ff_len: Self::EXPERT_FF_LEN_DEFAULT,
            shared_expert_ff_len: Self::SHARED_EXPERT_FF_LEN_DEFAULT,
        }
    }
}

// ─────────────────────────────────────────────────────────────────────────────
// Per-layer kind + persistent state
// ─────────────────────────────────────────────────────────────────────────────

#[derive(Clone, Copy, PartialEq, Eq)]
enum LayerKind {
    FullAttn,
    Ssm,
}

/// Persistent decode state per layer.
///
/// Public so the fat-station `/ssm-state/{save,load}` resume-anywhere plane can
/// serialize it (Qwen3.5-MoE / Qwen3-Next is a Gated-DeltaNet HYBRID: SSM layers
/// carry O(1) recurrent state, sparse full-attention layers carry a growing KV
/// cache — same MIXED-checkpoint shape as the Jamba/Falcon-H1 `HybridPipeline`).
pub enum LayerState {
    /// Gated-DeltaNet SSM layer.
    Ssm {
        /// Rolling causal conv history: [(conv_kernel-1) * conv_channels].
        /// conv_channels = q_dim + k_dim + v_dim (= 2048 + 2048 + 4096 = 8192).
        conv_buf: Vec<f32>,
        /// Recurrent outer-product state S[num_v_heads, state_size(k), state_size(v)].
        /// Laid out [vh * (dk*dv) + dk_idx * dv + dv_idx].
        state: Vec<f32>,
    },
    /// Full-attention layer: growing KV cache (per absolute position).
    Attn {
        /// [max_seq_len * num_kv_heads * head_dim].
        k_cache: Vec<f32>,
        v_cache: Vec<f32>,
    },
}

impl LayerState {
    fn reset(&mut self) {
        match self {
            LayerState::Ssm { conv_buf, state } => {
                conv_buf.fill(0.0);
                state.fill(0.0);
            }
            LayerState::Attn { k_cache, v_cache } => {
                k_cache.fill(0.0);
                v_cache.fill(0.0);
            }
        }
    }
}

/// A resolved tensor: its in-memory key + quant type.
#[derive(Clone)]
struct Tref {
    name: String,
    qtype: QType,
}

/// Per-layer tensor handles (names + qtypes). Optionals reflect which kind
/// of layer this is.
struct LayerWeights {
    kind: LayerKind,
    attn_norm: Tref,            // input norm (both kinds)
    post_attention_norm: Tref,  // pre-MoE norm (both kinds)

    // ── Full-attention only ──
    // Qwen3-Next FUSES the query and the output gate into `attn_q`: it emits
    // [q (num_heads*head_dim) | gate (num_heads*head_dim)] = 2*q_dim rows.
    // K and V are SEPARATE projections (NOT a fused qkv). There is NO separate
    // attn_gate tensor on full-attn layers (the gate is attn_q's second half).
    attn_q: Option<Tref>,      // [hidden, 2*q_dim] fused query + output gate
    attn_k: Option<Tref>,      // [hidden, kv_dim]
    attn_v: Option<Tref>,      // [hidden, kv_dim]
    attn_q_norm: Option<Tref>, // [head_dim]
    attn_k_norm: Option<Tref>, // [head_dim]
    attn_output: Option<Tref>, // o_proj [q_dim, hidden]

    // ── SSM only ──
    ssm_in: Option<Tref>,     // attn_qkv on SSM layers (in-projection [hidden, q+k+v])
    ssm_gate: Option<Tref>,   // attn_gate on SSM layers (z gate, [hidden, v_dim])
    ssm_conv1d: Option<Tref>, // [conv_kernel, conv_channels] depthwise
    ssm_a: Option<Tref>,      // [num_v_heads]
    ssm_alpha: Option<Tref>,  // [hidden, num_v_heads] -> a per v-head
    ssm_beta: Option<Tref>,   // [hidden, num_v_heads] -> beta per v-head
    ssm_dt_bias: Option<Tref>, // [num_v_heads]
    ssm_norm: Option<Tref>,   // [state_size] gated RMSNorm weight
    ssm_out: Option<Tref>,    // [v_dim, hidden]

    // ── MoE FFN (all layers) ──
    ffn_gate_inp: Tref,        // router [hidden, num_experts]
    ffn_gate_exps: Tref,       // [hidden, moe_ff, num_experts]
    ffn_up_exps: Tref,         // [hidden, moe_ff, num_experts]
    ffn_down_exps: Tref,       // [moe_ff, hidden, num_experts]
    ffn_gate_inp_shexp: Tref,  // shared gate [hidden]
    ffn_gate_shexp: Tref,      // [hidden, moe_ff]
    ffn_up_shexp: Tref,        // [hidden, moe_ff]
    ffn_down_shexp: Tref,      // [moe_ff, hidden]
}

// ─────────────────────────────────────────────────────────────────────────────
// Pipeline
// ─────────────────────────────────────────────────────────────────────────────

pub struct Qwen35MoePipeline {
    pub config: Qwen35MoeConfig,
    pub knot: KnotWeights,
    layers: Vec<LayerWeights>,
    /// Per-layer decode state. Public for the `/ssm-state` resume-anywhere plane.
    pub states: Vec<LayerState>,

    embed: Tref,
    final_norm: Tref,
    lm_head: Tref,

    /// Next-token logits from the most recent `forward_one`.
    pub last_logits: Vec<f32>,
}

impl Qwen35MoePipeline {
    #[cfg(not(target_arch = "wasm32"))]
    pub fn new(path: String) -> Result<Self> {
        let knot = KnotWeights::load(&path).map_err(|e| format!("knot load: {:?}", e))?;
        Self::from_knot(knot)
    }

    pub fn from_knot(knot: KnotWeights) -> Result<Self> {
        let cfg = match &knot.config {
            Some(c) => Qwen35MoeConfig::from_knot(c),
            None => return Err("qwen35moe knot must include a config block".to_string()),
        };
        if cfg.arch != "qwen35moe" {
            return Err(format!(
                "Qwen35MoePipeline: arch={:?} not supported (expected qwen35moe)",
                cfg.arch
            ));
        }

        // Top-level tensors.
        let tref = |name: &str| -> Tref {
            let qt = knot
                .backend
                .tensor_info(name)
                .map(|i| qtype_of(&i.tensor_type))
                .unwrap_or(QType::F32);
            Tref {
                name: name.to_string(),
                qtype: qt,
            }
        };
        let opt_tref = |name: &str| -> Option<Tref> {
            if knot.metadata.contains_key(name) {
                Some(tref(name))
            } else {
                None
            }
        };

        for n in ["token_embd_weight", "output_norm_weight"] {
            if !knot.metadata.contains_key(n) {
                return Err(format!("qwen35moe preflight: missing top-level tensor {:?}", n));
            }
        }
        let embed = tref("token_embd_weight");
        let final_norm = tref("output_norm_weight");
        // UNTIED lm_head: `output.weight` is present and distinct. Fall back to
        // the tied embedding if a future knot omits it.
        let lm_head = if knot.metadata.contains_key("output_weight") {
            tref("output_weight")
        } else {
            tref("token_embd_weight")
        };

        // v-head / k-head geometry for the SSM state buffer.
        let num_v_heads = cfg.ssm_time_step_rank; // 32
        let dk = cfg.ssm_state_size; // 128
        let dv = cfg.ssm_state_size; // 128
        // conv channels = q_dim + k_dim + v_dim.
        let k_dim = cfg.ssm_group_count * cfg.ssm_state_size; // 16*128 = 2048
        let q_dim_ssm = k_dim; // q shares k-head count
        let v_dim = cfg.ssm_inner_size; // 4096
        let conv_channels = q_dim_ssm + k_dim + v_dim; // 8192

        let mut layers = Vec::with_capacity(cfg.num_layers);
        let mut states = Vec::with_capacity(cfg.num_layers);

        for l in 0..cfg.num_layers {
            let n = |s: &str| format!("blk_{l}_{s}");
            // DISCRIMINATOR: full-attention iff `attn_output` present.
            // Full-attn layers carry separate attn_q/attn_k/attn_v + attn_output
            // and NO attn_qkv. SSM layers carry the fused attn_qkv in-projection
            // + attn_gate (z) and NO attn_output. (attn_qkv ALONE is not a
            // discriminator: only SSM layers have it, but checking attn_output
            // is the clean positive test for full-attn.)
            let attn_output_name = n("attn_output_weight");
            let is_attn = knot.metadata.contains_key(&attn_output_name);
            let kind = if is_attn {
                LayerKind::FullAttn
            } else {
                LayerKind::Ssm
            };

            // Required common tensors.
            for req in [n("attn_norm_weight"), n("post_attention_norm_weight")] {
                if !knot.metadata.contains_key(&req) {
                    return Err(format!("qwen35moe preflight: layer {l} missing {req:?}"));
                }
            }

            let lw = LayerWeights {
                kind,
                attn_norm: tref(&n("attn_norm_weight")),
                post_attention_norm: tref(&n("post_attention_norm_weight")),

                attn_q: if is_attn { opt_tref(&n("attn_q_weight")) } else { None },
                attn_k: if is_attn { opt_tref(&n("attn_k_weight")) } else { None },
                attn_v: if is_attn { opt_tref(&n("attn_v_weight")) } else { None },
                attn_q_norm: opt_tref(&n("attn_q_norm_weight")),
                attn_k_norm: opt_tref(&n("attn_k_norm_weight")),
                attn_output: opt_tref(&attn_output_name),

                ssm_in: if is_attn { None } else { opt_tref(&n("attn_qkv_weight")) },
                ssm_gate: if is_attn { None } else { opt_tref(&n("attn_gate_weight")) },
                ssm_conv1d: opt_tref(&n("ssm_conv1d_weight")),
                ssm_a: opt_tref(&n("ssm_a")),
                ssm_alpha: opt_tref(&n("ssm_alpha_weight")),
                ssm_beta: opt_tref(&n("ssm_beta_weight")),
                ssm_dt_bias: opt_tref(&n("ssm_dt_bias")),
                ssm_norm: opt_tref(&n("ssm_norm_weight")),
                ssm_out: opt_tref(&n("ssm_out_weight")),

                ffn_gate_inp: tref(&n("ffn_gate_inp_weight")),
                ffn_gate_exps: tref(&n("ffn_gate_exps_weight")),
                ffn_up_exps: tref(&n("ffn_up_exps_weight")),
                ffn_down_exps: tref(&n("ffn_down_exps_weight")),
                ffn_gate_inp_shexp: tref(&n("ffn_gate_inp_shexp_weight")),
                ffn_gate_shexp: tref(&n("ffn_gate_shexp_weight")),
                ffn_up_shexp: tref(&n("ffn_up_shexp_weight")),
                ffn_down_shexp: tref(&n("ffn_down_shexp_weight")),
            };
            layers.push(lw);

            states.push(match kind {
                LayerKind::Ssm => LayerState::Ssm {
                    conv_buf: vec![0.0; (cfg.ssm_conv_kernel - 1) * conv_channels],
                    state: vec![0.0; num_v_heads * dk * dv],
                },
                LayerKind::FullAttn => {
                    let kv = cfg.max_seq_len * cfg.num_kv_heads * cfg.head_dim;
                    LayerState::Attn {
                        k_cache: vec![0.0; kv],
                        v_cache: vec![0.0; kv],
                    }
                }
            });
        }

        Ok(Self {
            config: cfg,
            knot,
            layers,
            states,
            embed,
            final_norm,
            lm_head,
            last_logits: Vec::new(),
        })
    }

    pub fn get_logits(&self) -> &[f32] {
        &self.last_logits
    }

    pub fn reset_states(&mut self) {
        for s in &mut self.states {
            s.reset();
        }
    }

    // ── Weight fetch + matmul helpers ─────────────────────────────────

    /// Dequantize one full F32/F16-or-quant vector tensor (e.g. norms,
    /// 1-D bias/A) into f32.
    fn fetch_vec(&self, t: &Tref) -> Result<Vec<f32>> {
        let bytes = self
            .knot
            .backend
            .fetch_tensor(&t.name)
            .map_err(|e| format!("fetch {}: {:?}", t.name, e))?;
        match t.qtype {
            QType::F32 => Ok(bytes_to_f32_slice(&bytes).into_owned()),
            other => {
                // 1-D quant tensors are rare here, but handle generically by
                // a single-row dequant via mat_vec against an identity-free
                // path: dequantize using the row helpers element count.
                // Simpler: treat as a [n,1] matrix is wrong; instead dequant
                // the whole buffer through a 1-row matvec is not applicable.
                // All 1-D tensors in this knot are F32; bail loudly otherwise.
                Err(format!(
                    "fetch_vec: tensor {} has non-F32 qtype {:?} (unsupported for 1-D)",
                    t.name, other
                ))
            }
        }
    }

    /// `out[0..rows] = W · x` for a 2-D weight tensor stored row-major
    /// `[rows, cols]` (GGUF ne=[cols, rows]). Reuses the QType dispatch.
    fn matvec(&self, out: &mut [f32], x: &[f32], t: &Tref, rows: usize, cols: usize) -> Result<()> {
        let w = self
            .knot
            .backend
            .fetch_tensor(&t.name)
            .map_err(|e| format!("fetch {}: {:?}", t.name, e))?;
        mat_vec_dispatch_batch(&mut out[..rows], &x[..cols], &w, t.qtype, rows, cols, 1, rows);
        Ok(())
    }

    /// `out[0..rows] = W_e · x` for one expert `e` of a 3-D expert tensor
    /// `[cols, rows, num_experts]` (GGUF ne, expert = slowest axis). Slices
    /// the chosen expert's contiguous block at a quant-block boundary, then
    /// runs the same QType matvec dispatch.
    #[allow(clippy::too_many_arguments)]
    fn matvec_expert(
        &self,
        out: &mut [f32],
        x: &[f32],
        t: &Tref,
        rows: usize,
        cols: usize,
        expert: usize,
    ) -> Result<()> {
        let w = self
            .knot
            .backend
            .fetch_tensor(&t.name)
            .map_err(|e| format!("fetch {}: {:?}", t.name, e))?;
        let (block_bytes, block_elems) = block_layout(t.qtype);
        let elems_per_expert = rows * cols;
        if !elems_per_expert.is_multiple_of(block_elems) {
            return Err(format!(
                "matvec_expert: expert slice {} ({} elems) not block-aligned ({} elems/block)",
                t.name, elems_per_expert, block_elems
            ));
        }
        let bytes_per_expert = (elems_per_expert / block_elems) * block_bytes;
        let start = expert * bytes_per_expert;
        let end = start + bytes_per_expert;
        if end > w.len() {
            return Err(format!(
                "matvec_expert: expert {} slice [{}..{}] out of bounds (len {})",
                expert,
                start,
                end,
                w.len()
            ));
        }
        mat_vec_dispatch_batch(
            &mut out[..rows],
            &x[..cols],
            &w[start..end],
            t.qtype,
            rows,
            cols,
            1,
            rows,
        );
        Ok(())
    }

    /// Embed one token into `out` [hidden_dim].
    fn embed_token(&self, out: &mut [f32], token_id: u32) -> Result<()> {
        let hidden = self.config.hidden_dim;
        let bytes = self
            .knot
            .backend
            .fetch_tensor(&self.embed.name)
            .map_err(|e| format!("fetch token_embd: {:?}", e))?;
        let tok = token_id as usize;
        match self.embed.qtype {
            QType::F32 => {
                let emb = bytes_to_f32_slice(&bytes);
                let s = tok * hidden;
                out.copy_from_slice(&emb[s..s + hidden]);
            }
            QType::F16 => crate::model::dequantize_f16_row(out, &bytes, tok, hidden),
            QType::IQ2S => crate::iq_dequant::dequantize_iq2s_row(out, &bytes, tok, hidden),
            QType::IQ3S => crate::iq_dequant::dequantize_iq3s_row(out, &bytes, tok, hidden),
            QType::KAIJU1 => crate::kaiju_format::dequantize_kaiju1_row(out, &bytes, tok, hidden),
            QType::Q4K => crate::math::dequantize_q4k_row(out, &bytes, tok, hidden),
            QType::Q5_0 => crate::math::dequantize_q5_0_row(out, &bytes, tok, hidden),
            QType::Q5K => crate::math::dequantize_q5k_row(out, &bytes, tok, hidden),
            QType::Q6K => crate::math::dequantize_q6k_row(out, &bytes, tok, hidden),
            QType::Q8_0 => crate::math::dequantize_q8_0_row(out, &bytes, tok, hidden),
        }
        Ok(())
    }

    // ── Forward ───────────────────────────────────────────────────────

    /// Single-token incremental decode. `pos` is the absolute position
    /// (strictly increasing; prefill 0..N then decode N, N+1, …). Next-token
    /// logits land in `last_logits` (read via `get_logits`).
    pub fn forward_one(&mut self, token_id: u32, pos: usize) -> Result<()> {
        let hidden = self.config.hidden_dim;
        let eps = self.config.rms_norm_eps;
        let num_layers = self.config.num_layers;

        let mut x = vec![0.0f32; hidden];
        self.embed_token(&mut x, token_id)?;

        for l in 0..num_layers {
            let kind = self.layers[l].kind;
            // 1. Input RMSNorm.
            let attn_norm = self.fetch_vec(&self.layers[l].attn_norm.clone())?;
            let mut normed = vec![0.0f32; hidden];
            rms_norm(&mut normed, &x, &attn_norm, eps);

            // 2. Sequence-mixing sub-block → delta added to residual.
            let delta = match kind {
                LayerKind::FullAttn => self.attn_block(l, &normed, pos)?,
                LayerKind::Ssm => self.ssm_block(l, &normed)?,
            };
            for i in 0..hidden {
                x[i] += delta[i];
            }

            // 3. Pre-MoE RMSNorm (post_attention_norm).
            let post_norm = self.fetch_vec(&self.layers[l].post_attention_norm.clone())?;
            let mut normed2 = vec![0.0f32; hidden];
            rms_norm(&mut normed2, &x, &post_norm, eps);

            // 4. MoE FFN → delta added to residual.
            let moe = self.moe_block(l, &normed2)?;
            for i in 0..hidden {
                x[i] += moe[i];
            }
        }

        // Final norm + lm_head.
        let fnorm = self.fetch_vec(&self.final_norm.clone())?;
        let mut normed = vec![0.0f32; hidden];
        rms_norm(&mut normed, &x, &fnorm, eps);

        let vocab = self.config.vocab_size;
        let mut logits = vec![0.0f32; vocab];
        let lm = self.lm_head.clone();
        self.matvec(&mut logits, &normed, &lm, vocab, hidden)?;
        // No logit softcap for qwen35moe.
        self.last_logits = logits;
        Ok(())
    }

    // ── Full-attention sub-block (partial-RoPE GQA, gated o-proj) ──────
    fn attn_block(&mut self, l: usize, normed: &[f32], pos: usize) -> Result<Vec<f32>> {
        let cfg = &self.config;
        let hidden = cfg.hidden_dim;
        let nh = cfg.num_heads;
        let nkv = cfg.num_kv_heads;
        let hd = cfg.head_dim;
        let q_dim = nh * hd;
        let kv_dim = nkv * hd;
        let n_rot = cfg.rope_dim_count;
        let eps = cfg.rms_norm_eps;

        let lw = &self.layers[l];
        let q_t = lw.attn_q.clone().ok_or("attn layer missing attn_q")?;
        let k_t = lw.attn_k.clone().ok_or("attn layer missing attn_k")?;
        let v_t = lw.attn_v.clone().ok_or("attn layer missing attn_v")?;
        let out_t = lw.attn_output.clone().ok_or("attn layer missing attn_output")?;
        let q_norm_t = lw.attn_q_norm.clone();
        let k_norm_t = lw.attn_k_norm.clone();

        // Qwen3-Next FUSES the output gate into the query projection: attn_q
        // emits [q (q_dim) | gate (q_dim)] = 2*q_dim rows. Split after matmul.
        let mut q_and_gate = vec![0.0f32; 2 * q_dim];
        self.matvec(&mut q_and_gate, normed, &q_t, 2 * q_dim, hidden)?;
        let mut q = q_and_gate[..q_dim].to_vec();
        let gate = q_and_gate[q_dim..2 * q_dim].to_vec();

        // Separate K / V projections.
        let mut k = vec![0.0f32; kv_dim];
        let v = {
            let mut vv = vec![0.0f32; kv_dim];
            self.matvec(&mut vv, normed, &v_t, kv_dim, hidden)?;
            vv
        };
        self.matvec(&mut k, normed, &k_t, kv_dim, hidden)?;

        // Per-head Q/K RMSNorm (shared weight across heads, shape [head_dim]).
        if let Some(qn) = q_norm_t {
            let w = self.fetch_vec(&qn)?;
            crate::model::apply_per_head_rmsnorm(&mut q, &w, 1, nh, hd, eps);
        }
        if let Some(kn) = k_norm_t {
            let w = self.fetch_vec(&kn)?;
            crate::model::apply_per_head_rmsnorm(&mut k, &w, 1, nkv, hd, eps);
        }

        // Partial split-half NeoX RoPE: rotate only the first n_rot dims of
        // each head. `rope_neox` rotates a full head_dim; to rotate only the
        // first n_rot we treat each head's leading n_rot slice as a head of
        // size n_rot. We rebuild contiguous leading slices, rotate, copy back.
        // (VERIFY: split-half within the n_rot prefix; matches GGUF
        // rope.dimension_count partial-rotary convention.)
        rope_partial_inplace(&mut q, nh, hd, n_rot, pos, cfg.rope_theta);
        rope_partial_inplace(&mut k, nkv, hd, n_rot, pos, cfg.rope_theta);

        // Save K/V into the cache at absolute `pos`, then attend over [0..=pos].
        let scale = 1.0 / (hd as f32).sqrt();
        let kv_per_q = (nh / nkv).max(1);
        let mut attn_out = vec![0.0f32; q_dim];
        let max_seq = cfg.max_seq_len;

        if let LayerState::Attn { k_cache, v_cache } = &mut self.states[l] {
            let kv_stride = nkv * hd;
            if pos < max_seq {
                k_cache[pos * kv_stride..(pos + 1) * kv_stride].copy_from_slice(&k);
                v_cache[pos * kv_stride..(pos + 1) * kv_stride].copy_from_slice(&v);
            }
            let seq_len = pos + 1;
            for h in 0..nh {
                let kv_h = h / kv_per_q;
                let q_off = h * hd;
                let mut scores = vec![0.0f32; seq_len];
                for t in 0..seq_len {
                    let k_off = t * kv_stride + kv_h * hd;
                    scores[t] = dot_product(&q[q_off..q_off + hd], &k_cache[k_off..k_off + hd])
                        * scale;
                }
                softmax(&mut scores);
                let o_off = h * hd;
                for t in 0..seq_len {
                    let v_off = t * kv_stride + kv_h * hd;
                    let w = scores[t];
                    for i in 0..hd {
                        attn_out[o_off + i] += w * v_cache[v_off + i];
                    }
                }
            }
        }

        // Gated attention: attn_out *= sigmoid(gate) BEFORE o_proj. The gate is
        // the second half of the fused attn_q projection (computed above).
        for i in 0..q_dim {
            attn_out[i] *= sigmoid(gate[i]);
        }

        // O-projection back to hidden.
        let mut out = vec![0.0f32; hidden];
        self.matvec(&mut out, &attn_out, &out_t, hidden, q_dim)?;
        Ok(out)
    }

    // ── SSM (gated DeltaNet) sub-block ────────────────────────────────
    fn ssm_block(&mut self, l: usize, normed: &[f32]) -> Result<Vec<f32>> {
        let cfg = &self.config;
        let hidden = cfg.hidden_dim;
        let eps = cfg.rms_norm_eps;
        let n_vh = cfg.ssm_time_step_rank; // num_v_heads = 32
        let n_kh = cfg.ssm_group_count; // num_k_heads = 16
        let dk = cfg.ssm_state_size; // 128
        let dv = cfg.ssm_state_size; // 128
        let k_dim = n_kh * dk; // 2048
        let q_dim = k_dim; // 2048
        let v_dim = cfg.ssm_inner_size; // 4096
        let conv_channels = q_dim + k_dim + v_dim; // 8192
        let conv_k = cfg.ssm_conv_kernel; // 4

        let lw = &self.layers[l];
        let in_t = lw.ssm_in.clone().ok_or("ssm layer missing in-projection")?;
        let gate_t = lw.ssm_gate.clone().ok_or("ssm layer missing z gate")?;
        let conv_t = lw.ssm_conv1d.clone().ok_or("ssm layer missing conv1d")?;
        let a_t = lw.ssm_a.clone().ok_or("ssm layer missing ssm_a")?;
        let alpha_t = lw.ssm_alpha.clone().ok_or("ssm layer missing ssm_alpha")?;
        let beta_t = lw.ssm_beta.clone().ok_or("ssm layer missing ssm_beta")?;
        let dt_bias_t = lw.ssm_dt_bias.clone().ok_or("ssm layer missing ssm_dt_bias")?;
        let norm_t = lw.ssm_norm.clone().ok_or("ssm layer missing ssm_norm")?;
        let out_t = lw.ssm_out.clone().ok_or("ssm layer missing ssm_out")?;

        // In-projection → concat(q, k, v) of width conv_channels.
        let mut qkv = vec![0.0f32; conv_channels];
        self.matvec(&mut qkv, normed, &in_t, conv_channels, hidden)?;

        // z gate (value-dim).
        let mut z = vec![0.0f32; v_dim];
        self.matvec(&mut z, normed, &gate_t, v_dim, hidden)?;

        // a, beta: per-v-head projections from `normed`.
        let mut a = vec![0.0f32; n_vh];
        self.matvec(&mut a, normed, &alpha_t, n_vh, hidden)?;
        let mut beta_raw = vec![0.0f32; n_vh];
        self.matvec(&mut beta_raw, normed, &beta_t, n_vh, hidden)?;

        let ssm_a = self.fetch_vec(&a_t)?; // [n_vh]
        let dt_bias = self.fetch_vec(&dt_bias_t)?; // [n_vh]
        let conv_w = self.fetch_vec(&conv_t)?; // [conv_k, conv_channels]
        let ssm_norm_w = self.fetch_vec(&norm_t)?; // [dv]

        // Causal depthwise conv1d (kernel conv_k) over concat(q,k,v) + SiLU.
        // GGUF conv weight `ssm_conv1d` has GGUF dims=[conv_k, conv_channels]
        // i.e. ne0=conv_k (fastest), ne1=conv_channels (slowest) → in-memory
        // row-major as weight[ch * conv_k + kk] (channel-major, kernel
        // contiguous per channel — same layout as model_mamba's conv step).
        // conv_buf holds the last `hist` tokens token-major:
        // conv_buf[kk * conv_channels + ch], oldest at kk=0.
        let mut conv_out = vec![0.0f32; conv_channels];
        if let LayerState::Ssm { conv_buf, .. } = &mut self.states[l] {
            let hist = conv_k - 1;
            for ch in 0..conv_channels {
                let mut s = 0.0f32;
                for kk in 0..hist {
                    s += conv_buf[kk * conv_channels + ch] * conv_w[ch * conv_k + kk];
                }
                s += qkv[ch] * conv_w[ch * conv_k + (conv_k - 1)];
                conv_out[ch] = silu(s);
            }
            // advance history: shift [1..] → [0..hist-1], write current newest.
            if hist > 0 {
                conv_buf.copy_within(conv_channels.., 0);
                conv_buf[(hist - 1) * conv_channels..].copy_from_slice(&qkv);
            }
        }

        // Split conv output into q, k, v.
        let q = &conv_out[..q_dim];
        let k = &conv_out[q_dim..q_dim + k_dim];
        let vv = &conv_out[q_dim + k_dim..];

        // Gated DeltaNet recurrence (per v-head vh; its k-head kh = vh / (n_vh/n_kh)).
        // g = -exp(ssm_a) * softplus(a + dt_bias)   (decay, per v-head scalar)
        // S *= exp(g);  kv = Σ_dk S[dk,dv] * k[dk];  delta = (v - kv) * sigmoid(beta)
        // S += k ⊗ delta;  out[dv] = Σ_dk S[dk,dv] * q[dk]
        let vh_per_kh = (n_vh / n_kh).max(1); // 32/16 = 2
        let mut delta_out = vec![0.0f32; v_dim]; // raw recurrence output, per (vh, dv)

        if let LayerState::Ssm { state, .. } = &mut self.states[l] {
            for vh in 0..n_vh {
                let kh = vh / vh_per_kh;
                let k_head = &k[kh * dk..(kh + 1) * dk];
                let q_head = &q[kh * dk..(kh + 1) * dk];
                let v_head = &vv[vh * dv..(vh + 1) * dv];
                let beta = sigmoid(beta_raw[vh]);
                let g = -ssm_a[vh].exp() * softplus(a[vh] + dt_bias[vh]);
                let decay = g.exp();
                let s_base = vh * dk * dv;

                // S *= decay.
                for idx in s_base..s_base + dk * dv {
                    state[idx] *= decay;
                }
                // kv[dv] = Σ_dk S[dk,dv] * k[dk].
                let mut kv = vec![0.0f32; dv];
                for d_k in 0..dk {
                    let kk = k_head[d_k];
                    if kk == 0.0 {
                        continue;
                    }
                    let row = s_base + d_k * dv;
                    for d_v in 0..dv {
                        kv[d_v] += state[row + d_v] * kk;
                    }
                }
                // delta[dv] = (v[dv] - kv[dv]) * beta;  S[dk,dv] += k[dk] * delta[dv].
                let mut delta = vec![0.0f32; dv];
                for d_v in 0..dv {
                    delta[d_v] = (v_head[d_v] - kv[d_v]) * beta;
                }
                for d_k in 0..dk {
                    let kk = k_head[d_k];
                    if kk == 0.0 {
                        continue;
                    }
                    let row = s_base + d_k * dv;
                    for d_v in 0..dv {
                        state[row + d_v] += kk * delta[d_v];
                    }
                }
                // out[dv] = Σ_dk S[dk,dv] * q[dk].
                let out_base = vh * dv;
                for d_k in 0..dk {
                    let qk = q_head[d_k];
                    if qk == 0.0 {
                        continue;
                    }
                    let row = s_base + d_k * dv;
                    for d_v in 0..dv {
                        delta_out[out_base + d_v] += state[row + d_v] * qk;
                    }
                }
            }
        }

        // Gated RMSNorm per v-head: out = rmsnorm(out, ssm_norm) * silu(z).
        // ssm_norm weight is shared [dv]; z is [v_dim] gating value-dim.
        let mut gated = vec![0.0f32; v_dim];
        for vh in 0..n_vh {
            let base = vh * dv;
            let head = &delta_out[base..base + dv];
            let mut ss = 0.0f32;
            for &val in head.iter() {
                ss += val * val;
            }
            let inv = 1.0 / (ss / dv as f32 + eps).sqrt();
            for d_v in 0..dv {
                let normed_v = head[d_v] * inv * ssm_norm_w[d_v];
                gated[base + d_v] = normed_v * silu(z[base + d_v]);
            }
        }

        // y = ssm_out · gated  (v_dim → hidden).
        let mut out = vec![0.0f32; hidden];
        self.matvec(&mut out, &gated, &out_t, hidden, v_dim)?;
        Ok(out)
    }

    // ── MoE FFN sub-block ─────────────────────────────────────────────
    fn moe_block(&mut self, l: usize, x: &[f32]) -> Result<Vec<f32>> {
        let cfg = &self.config;
        let hidden = cfg.hidden_dim;
        let n_exp = cfg.num_experts;
        let top_k = cfg.num_experts_per_tok;
        let moe_ff = cfg.expert_ff_len;
        let sh_ff = cfg.shared_expert_ff_len;

        let lw = &self.layers[l];
        let router_t = lw.ffn_gate_inp.clone();
        let gate_exps_t = lw.ffn_gate_exps.clone();
        let up_exps_t = lw.ffn_up_exps.clone();
        let down_exps_t = lw.ffn_down_exps.clone();
        let sh_gate_inp_t = lw.ffn_gate_inp_shexp.clone();
        let sh_gate_t = lw.ffn_gate_shexp.clone();
        let sh_up_t = lw.ffn_up_shexp.clone();
        let sh_down_t = lw.ffn_down_shexp.clone();

        // Router: logits[e] = router · x; softmax over all experts; top-k;
        // renormalize the k weights (norm_topk_prob = true).
        let mut logits = vec![0.0f32; n_exp];
        self.matvec(&mut logits, x, &router_t, n_exp, hidden)?;
        let mut probs = logits.clone();
        softmax(&mut probs);

        let k = top_k.min(n_exp);
        let mut chosen: Vec<(usize, f32)> = Vec::with_capacity(k);
        let mut used = vec![false; n_exp];
        for _ in 0..k {
            let mut best = usize::MAX;
            let mut best_p = f32::NEG_INFINITY;
            for (e, &p) in probs.iter().enumerate() {
                if !used[e] && p > best_p {
                    best_p = p;
                    best = e;
                }
            }
            if best == usize::MAX {
                break;
            }
            used[best] = true;
            chosen.push((best, probs[best]));
        }
        let wsum: f32 = chosen.iter().map(|(_, w)| *w).sum();
        let inv_wsum = if wsum > 0.0 { 1.0 / wsum } else { 0.0 };

        let mut out = vec![0.0f32; hidden];
        let mut gate_buf = vec![0.0f32; moe_ff];
        let mut up_buf = vec![0.0f32; moe_ff];
        let mut down_buf = vec![0.0f32; hidden];
        for (e, w) in chosen {
            let w = w * inv_wsum;
            // gate_e: hidden -> moe_ff ; up_e: hidden -> moe_ff.
            self.matvec_expert(&mut gate_buf, x, &gate_exps_t, moe_ff, hidden, e)?;
            self.matvec_expert(&mut up_buf, x, &up_exps_t, moe_ff, hidden, e)?;
            for i in 0..moe_ff {
                gate_buf[i] = silu(gate_buf[i]) * up_buf[i];
            }
            // down_e: moe_ff -> hidden.
            self.matvec_expert(&mut down_buf, &gate_buf, &down_exps_t, hidden, moe_ff, e)?;
            for i in 0..hidden {
                out[i] += w * down_buf[i];
            }
        }

        // Shared expert (always on): ys = down(silu(gate·x) * up·x);
        // shared_gate = sigmoid(gate_inp_shexp · x); out += shared_gate * ys.
        let mut sh_gate = vec![0.0f32; sh_ff];
        let mut sh_up = vec![0.0f32; sh_ff];
        self.matvec(&mut sh_gate, x, &sh_gate_t, sh_ff, hidden)?;
        self.matvec(&mut sh_up, x, &sh_up_t, sh_ff, hidden)?;
        for i in 0..sh_ff {
            sh_gate[i] = silu(sh_gate[i]) * sh_up[i];
        }
        let mut ys = vec![0.0f32; hidden];
        self.matvec(&mut ys, &sh_gate, &sh_down_t, hidden, sh_ff)?;
        // shared gate is a scalar logit: gate_inp_shexp is [hidden] -> 1.
        let sh_gate_inp = self.fetch_vec(&sh_gate_inp_t)?;
        let mut sh_logit = 0.0f32;
        for i in 0..hidden {
            sh_logit += sh_gate_inp[i] * x[i];
        }
        let sh_w = sigmoid(sh_logit);
        for i in 0..hidden {
            out[i] += sh_w * ys[i];
        }
        Ok(out)
    }
}

/// Partial split-half NeoX RoPE applied in-place to a packed
/// `[num_heads * head_dim]` buffer: only the first `n_rot` dims of each head
/// rotate (split-half: dim `i` pairs with dim `i + n_rot/2` within the
/// rotated prefix); the remaining `head_dim - n_rot` dims pass through.
fn rope_partial_inplace(
    buf: &mut [f32],
    num_heads: usize,
    head_dim: usize,
    n_rot: usize,
    pos: usize,
    theta: f32,
) {
    if n_rot == 0 {
        return;
    }
    // Rotate the leading n_rot of each head via a temporary contiguous pack,
    // reusing `rope_neox` (split-half over the passed head_dim == n_rot).
    let mut tmp = vec![0.0f32; num_heads * n_rot];
    for h in 0..num_heads {
        let src = &buf[h * head_dim..h * head_dim + n_rot];
        tmp[h * n_rot..(h + 1) * n_rot].copy_from_slice(src);
    }
    // rope_neox rotates q and k symmetrically; pass tmp as both (k slice unused
    // here would still be rotated, so pass a throwaway for k of len 0 heads).
    let mut dummy: [f32; 0] = [];
    rope_neox(&mut tmp, &mut dummy, pos, num_heads, 0, n_rot, theta);
    for h in 0..num_heads {
        buf[h * head_dim..h * head_dim + n_rot]
            .copy_from_slice(&tmp[h * n_rot..(h + 1) * n_rot]);
    }
}
